// Extract product listings from Amazon search results
const products = [];
const items = document.querySelectorAll('[data-component-type="s-search-result"]');
items.forEach((item, i) => {
  if (i >= 10) return;
  const title = item.querySelector('h2 a span')?.textContent?.trim() || '';
  const price = item.querySelector('.a-price .a-offscreen')?.textContent?.trim() || '';
  const rating = item.querySelector('.a-icon-star-small .a-icon-alt')?.textContent?.trim() || 
                 item.querySelector('[class*="star"] .a-icon-alt')?.textContent?.trim() || '';
  const reviewCount = item.querySelector('[aria-label*="stars"] + span')?.textContent?.trim() || 
                      item.querySelector('.a-size-base.s-underline-text')?.textContent?.trim() || '';
  const brand = item.querySelector('.a-size-base-plus.a-color-base')?.textContent?.trim() || '';
  const asin = item.getAttribute('data-asin') || '';
  if (title) products.push({ asin, title, brand, price, rating, reviewCount });
});
return JSON.stringify(products, null, 2);

